const OUTDIR="/tmp/claude-1000/-data-Brilliant-genomics-department/eb8d91f3-1707-45de-a10d-2de68fef6627/scratchpad/growthdb_work/lit/extractions";
const BATCH=8;
const batches=[];for(let i=0;i<PAPERS.length;i+=BATCH)batches.push({idx:batches.length,paths:PAPERS.slice(i,i+BATCH)});
log(`Mining ${PAPERS.length} growth papers in ${batches.length} batches`);
const SUMMARY={type:'object',properties:{papers_processed:{type:'integer'},records_found:{type:'integer'},note:{type:'string'}},required:['papers_processed','records_found','note'],additionalProperties:false};
const BODY="You extract EXPERIMENTAL GROWTH DATA from microbiology / metabolic-modelling papers, for a curated database used to constrain genome-scale metabolic models. Accuracy over recall; compute a derived rate ONLY from numbers explicitly in the paper; never invent.\n\nRead each of these JATS XML papers (use the Read tool):\n${LIST}\n\nFor EACH paper, extract every distinct GROWTH OBSERVATION of a prokaryote where a growth rate and/or a substrate uptake rate and/or a product secretion rate is REPORTED or can be CALCULATED from data the paper provides. For each observation capture:\n- organism (species) + strain\n- medium: name; and its composition if stated (compounds + concentrations)\n- conditions: culture_mode (batch/fed-batch/chemostat/retentostat), oxygen (aerobic/anaerobic/microaerophilic/anoxic), temperature_C, pH, dilution_rate_per_h (if chemostat)\n- growth_rate_per_h (mu) and/or doubling_time_h \u2014 REPORTED, or CALCULATED (mu = ln2/doubling_time; at chemostat steady state mu = dilution rate; mu from an OD/CFU time-course slope). Set growth_method reported|calculated.\n- uptake_rates: specific substrate consumption qS as [{compound, rate, units (prefer mmol/gDW/h), method}]; may be calculated (qS = mu / Yxs, or delta-substrate/(biomass x time)).\n- secretion_rates: specific production qP [{compound, rate, units, method}]; may be calculated from product yield x mu.\n- source_snippet: verbatim proof text (<=300 chars).\n- confidence (high|medium|low) and curation_notes explaining ANY calculation (state the formula + the input numbers you used from the paper).\n\nSTRICT: compute a rate only if the required numbers are explicitly present; record the formula + inputs in curation_notes. Citation from article-meta (article-title, doi, journal, year, first surname); PMCID = the file basename.\n\nWrite JSON to this exact file (Write tool): ${OUTDIR}/batch_${IDX}.json\n{\"records\":[{\"pmcid\",\"paper_title\",\"first_author\",\"doi\",\"journal\",\"year\",\"organism\",\"strain\",\"medium_name\",\"medium_composition\":[{\"name\",\"amount\",\"unit\"}],\"culture_mode\",\"oxygen\",\"temperature_C\",\"pH\",\"dilution_rate_per_h\",\"growth_rate_per_h\",\"doubling_time_h\",\"growth_method\",\"uptake_rates\":[{\"compound\",\"rate\",\"units\",\"method\"}],\"secretion_rates\":[{\"compound\",\"rate\",\"units\",\"method\"}],\"source_snippet\",\"confidence\",\"curation_notes\"}]}\nWrite {\"records\":[]} if a batch yields nothing.\n\nThen return: papers_processed, records_found, note.";
function prompt(b){return BODY.replace('${LIST}',b.paths.map(p=>'- '+p).join('\n')).replace('${OUTDIR}',OUTDIR).replace('${IDX}',String(b.idx));}
const results=await parallel(batches.map(b=>()=>agent(prompt(b),{label:`growth:${b.idx}`,phase:'Extract',model:'sonnet',schema:SUMMARY})));
const ok=results.filter(Boolean);const tr=ok.reduce((s,r)=>s+(r.records_found||0),0);const tp=ok.reduce((s,r)=>s+(r.papers_processed||0),0);
log(`Done: ${ok.length}/${batches.length} agents, ${tr} records from ${tp} papers`);
return {batches:batches.length,agents_ok:ok.length,papers_processed:tp,total_records:tr,outdir:OUTDIR};
